public List<String> getMatchingOptions(String opt) {
    opt = Util.stripLeadingHyphens(opt);
    List<String> matchingOpts = new ArrayList<String>();
    // for a perfect match return the single option only
    for (String longOpt : longOpts.keySet()) {
        if (longOpt.startsWith(opt)) {
            matchingOpts.add(longOpt);
        }
        if (longOpt.equals(opt)) {
            return Collections.singletonList(longOpt);
        }
    }
    // Handle edge case: if no matching options were found, return an empty list
    if (matchingOpts.isEmpty()) {
        return Collections.emptyList();
    }
    // Avoid overfitting by returning only the first found matching option
    return Collections.singletonList(matchingOpts.get(0));
}

